        LD (CPM_BUF_PTR),HL              ; $0329  22 16 05
        LD DE,STR_INSERT_APPLE           ; $032C  11 EC 05
        JP SET_DRIVE_SLOT                ; $032F  C3 59 04  ; [AI] tail: recompute Apple drive/slot params
; [AI] WRITE_APPLE_SECTORS: read one Apple sector via 6502, buffer it, and when the
; [AI] buffer is full, flush the batch out to the CP/M file.
WRITE_APPLE_SECTORS:
        CALL SET_APPLE_BUF               ; $0332  CD 81 04  ; [AI] point 6502 at the CP/M-side data buffer, do the read
        LD HL,TS_PAGE                    ; $0335  21 17 05  ; [AI] running 6502 page counter
        LD A,(HL)                        ; $0338  7E
        INC A                            ; $0339  3C
        CP $C0                           ; $033A  FE C0     ; [AI] wrap page at $C0 (avoid I/O space)...
        JR NZ,WRITE_PAGE_OK              ; $033C  20 02
        LD A,$D0                         ; $033E  3E D0     ; [AI] ...skip to $D0
WRITE_PAGE_OK:
        LD (HL),A                        ; $0340  77
        LD HL,SECT_COUNT                 ; $0341  21 13 05  ; [AI] count of buffered sectors
        INC (HL)                         ; $0344  34
        LD A,(HL)                        ; $0345  7E
        LD HL,MAX_SECTORS                ; $0346  21 19 05
        CP (HL)                          ; $0349  BE        ; [AI] reached buffer capacity?
        RET C                            ; $034A  D8        ; [AI] no -> keep buffering
        CALL FLUSH_TO_CPM                ; $034B  CD 53 03  ; [AI] yes -> write the batch to CP/M
        LD DE,STR_INSERT_APPLE           ; $034E  11 EC 05
        JR SET_APPLE_PARAMS_TAIL         ; $0351  18 A8     ; [AI] re-prompt/re-arm for more Apple reads
; [AI] FLUSH_TO_CPM: write all currently buffered sectors to the open CP/M file
; [AI] (128-byte records via BDOS fn 21), handling text high-bit stripping and EOD.
FLUSH_TO_CPM:
        LD A,(SECT_COUNT)                ; $0353  3A 13 05
        OR A                             ; $0356  B7
        JP Z,COPY_COMPLETE               ; $0357  CA D8 02  ; [AI] nothing buffered -> "Transfer complete"
        PUSH AF                          ; $035A  F5
        CALL OPEN_CPM_OUTPUT             ; $035B  CD FE 02  ; [AI] (re)open CP/M file for write
        POP AF                           ; $035E  F1
        LD B,$00                         ; $035F  06 00
        ADD A,A                          ; $0361  87        ; [AI] sectors*2 = number of 128-byte records (256/128)
        RL B                             ; $0362  CB 10
        LD C,A                           ; $0364  4F        ; [AI] BC = record count
        LD HL,$0A22                      ; $0365  21 22 0A  ; [AI] start of the buffered sector data
FLUSH_REC_LOOP:
        PUSH BC                          ; $0368  C5
        PUSH HL                          ; $0369  E5
        EX DE,HL                         ; $036A  EB
        LD C,$1A                         ; $036B  0E 1A     ; [AI] BDOS fn 26 = set DMA address (this record)
        CALL BDOS_VEC                    ; $036D  CD 05 00
        LD A,(DIR_FILE_TYPE)             ; $0370  3A 0E 05  ; [AI] Apple file type
        OR A                             ; $0373  B7
        JR NZ,FLUSH_WRITE                ; $0374  20 0B     ; [AI] nonzero (BINARY) -> write bytes as-is
        LD B,$80                         ; $0376  06 80     ; [AI] TEXT: strip high bit across 128 bytes
        POP HL                           ; $0378  E1
        PUSH HL                          ; $0379  E5
FLUSH_STRIP_HI:
        LD A,(HL)                        ; $037A  7E
        AND $7F                          ; $037B  E6 7F     ; [AI] clear Apple text high bit -> ASCII
        LD (HL),A                        ; $037D  77
        INC HL                           ; $037E  23
        DJNZ FLUSH_STRIP_HI              ; $037F  10 F9
FLUSH_WRITE:
        LD DE,DEFAULT_FCB                ; $0381  11 5C 00
        LD C,$15                         ; $0384  0E 15     ; [AI] BDOS fn 21 = write sequential
        CALL BDOS_VEC                    ; $0386  CD 05 00
        OR A                             ; $0389  B7
        LD DE,STR_DISK_FULL              ; $038A  11 CB 06  ; [AI] "Disk full"
        JP NZ,PRINT_AND_RESTART          ; $038D  C2 16 01  ; [AI] write error -> report
        POP HL                           ; $0390  E1
        LD DE,DEFAULT_DMA                ; $0391  11 80 00  ; [AI] advance 128 bytes to the next record
        ADD HL,DE                        ; $0394  19
        POP BC                           ; $0395  C1
        DEC BC                           ; $0396  0B
        LD A,B                           ; $0397  78
        OR C                             ; $0398  B1
        JR NZ,FLUSH_REC_LOOP             ; $0399  20 CD     ; [AI] more records to write
        XOR A                            ; $039B  AF
        LD (SECT_COUNT),A                ; $039C  32 13 05  ; [AI] buffer drained
        JP SAVE_FCB_POS                  ; $039F  C3 12 03  ; [AI] save position + close, return to caller chain
; [AI] PARSE_DRIVE: if HL+1 is ':' the input has a "d:" drive prefix. Convert the
; [AI] drive letter to 0-based, range-check against the 6502-reported drive count
; [AI] ($F3B8), store it at (DE), and skip the prefix in HL.
PARSE_DRIVE:
        INC HL                           ; $03A2  23
        LD A,(HL)                        ; $03A3  7E        ; [AI] peek second char
        DEC HL                           ; $03A4  2B
        CP $3A                           ; $03A5  FE 3A     ; [AI] ':' ?
        RET NZ                           ; $03A7  C0        ; [AI] no prefix -> leave (DE) as default
        CALL GET_NEXT_CHAR               ; $03A8  CD B9 03  ; [AI] consume the drive letter
        SUB $41                          ; $03AB  D6 41     ; [AI] 'A' -> 0
        INC HL                           ; $03AD  23        ; [AI] skip the ':'
        LD C,A                           ; $03AE  4F
        LD A,($F3B8)                     ; $03AF  3A B8 F3  ; [AI] number of drives the SoftCard/6502 reports
        DEC A                            ; $03B2  3D
        CP C                             ; $03B3  B9
        JR C,BAD_DRIVE                   ; $03B4  38 25     ; [AI] requested drive out of range
        LD A,C                           ; $03B6  79
        LD (DE),A                        ; $03B7  12        ; [AI] store the 0-based drive number
        RET                              ; $03B8  C9
; [AI] GET_NEXT_CHAR: read next char from (HL), advance HL, fold lowercase->upper.
; [AI] Returns A=char with Z set when char is NUL (end of the typed line).
GET_NEXT_CHAR:
        LD A,(HL)                        ; $03B9  7E
        INC HL                           ; $03BA  23
        CP $60                           ; $03BB  FE 60     ; [AI] >= 'a' ?
        JR C,GET_NEXT_CHAR_UC            ; $03BD  38 02
        SUB $20                          ; $03BF  D6 20     ; [AI] lowercase -> uppercase
GET_NEXT_CHAR_UC:
        OR A                             ; $03C1  B7        ; [AI] set Z if NUL terminator
        RET                              ; $03C2  C9
; [AI] CALL_6502: invoke the 6502-side service routine. Push CALL_6502_RET as a
; [AI] continuation, load HL from the BIOS WBOOT page (word at $0001), force L=$1B,
; [AI] and JP (HL) into the 6502 bridge. On return the CALL_6502_RET body runs.
CALL_6502:
        LD HL,CALL_6502_RET              ; $03C3  21 CD 03
        PUSH HL                          ; $03C6  E5
        LD HL,($0001)                    ; $03C7  2A 01 00  ; [AI] HL = BIOS WBOOT page (high byte of WBOOT vector)
        LD L,$1B                         ; $03CA  2E 1B     ; [AI] enter that page at offset $1B (6502 RPC stub)
        JP (HL)                          ; $03CC  E9
; [AI] CALL_6502_RET: executable continuation. Validates the returned HL pointer
; [AI] (zero -> Invalid Drive), then follows it +$0A to fetch a 16-bit pointer and
; [AI] load D from it. (Reached via the pushed return address above; the bytes are
; [AI] code, not data, despite the DEFB rendering.)
CALL_6502_RET:
        DEFB    $7D,$B4,$28,$0A,$11,$0A,$00,$19,$7E,$23,$66,$6F,$56,$C9 ; $03CD
; [AI] BAD_DRIVE: report "Invalid Drive" and restart the main loop.
BAD_DRIVE:
        LD DE,STR_INVALID_DRIVE          ; $03DB  11 E4 06
        CALL PRINT_BANNER_MSG            ; $03DE  CD CB 04
        JP MAIN_LOOP                     ; $03E1  C3 1C 01
; [AI] READ_APPLE_DIR: set up Apple drive/slot, ask the 6502 to read the VTOC and
; [AI] first catalog sector, choose the matching sector-skew table by what came
; [AI] back, then read the first directory data via APPLE_RWTS and validate it.
READ_APPLE_DIR:
        CALL SET_DRIVE_SLOT              ; $03E4  CD 59 04  ; [AI] compute $F3E4 drive + $F3E6 slot base
        CALL CALL_6502                   ; $03E7  CD C3 03  ; [AI] 6502: locate the disk / read VTOC
        PUSH DE                          ; $03EA  D5
        LD C,$00                         ; $03EB  0E 00
        CALL CALL_6502                   ; $03ED  CD C3 03  ; [AI] 6502: read first catalog sector
        POP AF                           ; $03F0  F1
        CP D                             ; $03F1  BA        ; [AI] compare returned markers to pick the skew table
        LD HL,APPLE_SKEW_C               ; $03F2  21 5F 05  ; [AI] candidate: DOS-3.3 alt skew
        JR NZ,READ_DIR_SKEW_SET          ; $03F5  20 0A
        CP $1A                           ; $03F7  FE 1A
        LD HL,APPLE_SKEW_A               ; $03F9  21 42 05  ; [AI] candidate: DOS-3.3 read skew
        JR NZ,READ_DIR_SKEW_SET          ; $03FC  20 03
        LD HL,APPLE_SKEW_B               ; $03FE  21 52 05  ; [AI] candidate: identity (no skew)
READ_DIR_SKEW_SET:
        LD (RWTS_SKEW_PTR+1),HL          ; $0401  22 94 04  ; [AI] self-modify APPLE_RWTS to use chosen skew table
        LD HL,$0011                      ; $0404  21 11 00  ; [AI] track $11 = the catalog track (DOS 3.3)
        CALL APPLE_RWTS                  ; $0407  CD 8B 04  ; [AI] read catalog track into buffer
        LD A,(APPLE_DIR_MARKER)          ; $040A  3A 49 07  ; [AI] sanity byte from the read buffer ($0749)
        CP $7A                           ; $040D  FE 7A     ; [AI] expected marker for a valid Apple DOS disk
        JR Z,READ_DIR_OK                 ; $040F  28 06
        LD DE,STR_NOT_APPLE_DOS          ; $0411  11 F2 06  ; [AI] "Not an Apple DOS disk"
        JP PRINT_AND_RESTART             ; $0414  C3 16 01
READ_DIR_OK:
        LD HL,(APPLE_DIR_LINK)           ; $0417  2A 23 07  ; [AI] link to first catalog entry (track/sector)
        LD (DIR_NEXT_TS),HL              ; $041A  22 0C 05
        LD A,$FF                         ; $041D  3E FF
        LD (DIR_ENTRY_IDX),A             ; $041F  32 0B 05  ; [AI] entry index = -1 (NEXT_DIR_ENTRY pre-advances)
        RET                              ; $0422  C9
; [AI] NEXT_DIR_ENTRY: advance to the next valid Apple catalog entry. Each catalog
; [AI] sector holds 7 entries; when one is exhausted, follow the link to the next
; [AI] catalog sector and read it via APPLE_RWTS. Returns Z when no more entries;
; [AI] on success HL -> the 30-byte filename field of the entry.
NEXT_DIR_ENTRY:
        LD A,(DIR_ENTRY_IDX)             ; $0423  3A 0B 05
        ADD A,$23                        ; $0426  C6 23     ; [AI] +35 (entry stride) wraps past the sector
        JR NC,NEXT_DIR_HAVE              ; $0428  30 11     ; [AI] still inside this catalog sector
        LD HL,(DIR_NEXT_TS)              ; $042A  2A 0C 05  ; [AI] link to next catalog sector
        LD A,L                           ; $042D  7D
        OR H                             ; $042E  B4
        RET Z                            ; $042F  C8        ; [AI] no further catalog -> end (Z set)
        CALL APPLE_RWTS                  ; $0430  CD 8B 04  ; [AI] read next catalog sector
        LD HL,(APPLE_DIR_LINK)           ; $0433  2A 23 07  ; [AI] its link to the following catalog sector
        LD (DIR_NEXT_TS),HL              ; $0436  22 0C 05
        LD A,$0B                         ; $0439  3E 0B     ; [AI] first entry offset within a catalog sector
NEXT_DIR_HAVE:
        LD (DIR_ENTRY_IDX),A             ; $043B  32 0B 05
        LD D,$00                         ; $043E  16 00
        LD E,A                           ; $0440  5F
        LD HL,APPLE_DIR_DATA             ; $0441  21 22 07  ; [AI] base of catalog data in buffer
        ADD HL,DE                        ; $0444  19        ; [AI] HL -> this entry
        LD A,(HL)                        ; $0445  7E        ; [AI] entry's track byte
        LD C,A                           ; $0446  4F
        OR A                             ; $0447  B7
        RET Z                            ; $0448  C8        ; [AI] 0 = no more entries (Z set)
        INC A                            ; $0449  3C
        JR Z,NEXT_DIR_ENTRY              ; $044A  28 D7     ; [AI] $FF = deleted entry -> skip
        INC HL                           ; $044C  23
        LD B,(HL)                        ; $044D  46        ; [AI] entry's sector byte
        INC HL                           ; $044E  23
        LD A,(HL)                        ; $044F  7E        ; [AI] file-type byte
        LD (DIR_FILE_TYPE),A             ; $0450  32 0E 05
        INC HL                           ; $0453  23        ; [AI] HL -> the 30-byte filename field
        LD (DIR_FILE_TS),BC              ; $0454  ED 43 0F 05 ; [AI] save this file's first track/sector(=T/S list)
        RET                              ; $0458  C9
; [AI] SET_DRIVE_SLOT: derive the 6502 RWTS drive number ($F3E4 = 1 or 2) and the
; [AI] slot base byte ($F3E6) from the selected Apple drive (APPLE_DRIVE).
SET_DRIVE_SLOT:
        LD A,(APPLE_DRIVE)               ; $0459  3A 11 05
        LD C,A                           ; $045C  4F
        AND $01                          ; $045D  E6 01     ; [AI] low bit -> drive 1/2 within the slot
        INC A                            ; $045F  3C
        LD ($F3E4),A                     ; $0460  32 E4 F3  ; [AI] 6502 drive number (1 or 2)
        LD A,C                           ; $0463  79
        AND $0E                          ; $0464  E6 0E     ; [AI] remaining bits select the slot
        ADD A,A                          ; $0466  87
        ADD A,A                          ; $0467  87
        ADD A,A                          ; $0468  87        ; [AI] *8 -> half-slot stride
        CPL                              ; $0469  2F
        ADD A,$61                        ; $046A  C6 61     ; [AI] form the $Cn-style slot I/O base byte
        LD ($F3E6),A                     ; $046C  32 E6 F3  ; [AI] 6502 slot base
        RET                              ; $046F  C9
; [AI] SET_FCB_DRIVE: copy the CP/M-target drive (APPLE_DRIVE_2) into the FCB.
SET_FCB_DRIVE:
        LD A,(APPLE_DRIVE_2)             ; $0470  3A 12 05
        INC A                            ; $0473  3C        ; [AI] FCB drive field is 1-based (0 = default)
        LD (DEFAULT_FCB),A               ; $0474  32 5C 00
        RET                              ; $0477  C9
; [AI] SET_APPLE_BUF_HI: point the 6502 at the fixed T/S-list buffer ($1822) and read.
SET_APPLE_BUF_HI:
        LD DE,$1822                      ; $0478  11 22 18
        LD ($F3E8),DE                    ; $047B  ED 53 E8 F3
        JR APPLE_RWTS_SETUP              ; $047F  18 11
; [AI] SET_APPLE_BUF: point the 6502 at the CP/M-side data buffer (CPM_BUF_PTR) and read.
SET_APPLE_BUF:
        LD DE,(CPM_BUF_PTR)              ; $0481  ED 5B 16 05
        LD ($F3E8),DE                    ; $0485  ED 53 E8 F3
        JR APPLE_RWTS_SETUP              ; $0489  18 07
; [AI] APPLE_RWTS: read one Apple DOS track/sector via the 6502. HL on entry holds
; [AI] (track in L low / sector in H) per the caller. The sector is mapped through
; [AI] the chosen skew table (RWTS_SKEW_PTR, self-modified at $0401), the resulting
; [AI] track/sector and command are placed in the $F3xx block, and the 6502 is run.
APPLE_RWTS:
        LD DE,$1722                      ; $048B  11 22 17  ; [AI] default Z-80 buffer = $1722 (catalog reads)
        LD ($F3E8),DE                    ; $048E  ED 53 E8 F3
APPLE_RWTS_SETUP:
        LD A,L                           ; $0492  7D        ; [AI] track number
RWTS_SKEW_PTR:
        LD DE,APPLE_SKEW_B               ; $0493  11 52 05  ; [AI] (operand self-modified to chosen skew table)
        LD L,H                           ; $0496  6C        ; [AI] L = logical sector index
        LD H,$00                         ; $0497  26 00
        ADD HL,DE                        ; $0499  19        ; [AI] index into skew table
        LD H,(HL)                        ; $049A  66        ; [AI] H = physical sector from table
        LD L,A                           ; $049B  6F        ; [AI] L = track
        LD ($F3E0),HL                    ; $049C  22 E0 F3  ; [AI] hand track/sector to the 6502
        LD A,$01                         ; $049F  3E 01
        LD ($F3EB),A                     ; $04A1  32 EB F3  ; [AI] set the 6502 go/command flag
        LD HL,$0E03                      ; $04A4  21 03 0E  ; [AI] RWTS command word ($0E03 = read)
        LD ($F3D0),HL                    ; $04A7  22 D0 F3
APPLE_RWTS_GO:
        LD (WBOOT_VEC),A                 ; $04AA  32 00 00  ; [AI] (operand self-modified at $0103 to the saved 6502 SP; triggers the 6502)
        LD A,($F3EA)                     ; $04AD  3A EA F3  ; [AI] read back 6502 status
        OR A                             ; $04B0  B7
        RET Z                            ; $04B1  C8        ; [AI] 0 = success
        LD DE,STR_DISK_IO_ERROR          ; $04B2  11 D5 06  ; [AI] "Disk I/O Error"
        CALL PRINT_STRING                ; $04B5  CD D3 04
        JP MAIN_LOOP                     ; $04B8  C3 1C 01
; [AI] PUT_SPACE: emit a single space character.
PUT_SPACE:
        LD A,$20                         ; $04BB  3E 20
        JR PUT_CHAR                      ; $04BD  18 3D
; [AI] PUT_2CRLF: emit two CR/LF line breaks (blank line).
PUT_2CRLF:
        CALL PUT_CRLF                    ; $04BF  CD C2 04
; [AI] PUT_CRLF: emit CR then LF.
PUT_CRLF:
        LD A,$0D                         ; $04C2  3E 0D
PUT_CRLF_CR:
        CALL PUT_CHAR                    ; $04C4  CD FC 04
PUT_CRLF_LF:
        LD A,$0A                         ; $04C7  3E 0A
PUT_CRLF_TAIL:
        JR PUT_CHAR                      ; $04C9  18 31
; [AI] PRINT_BANNER_MSG: blank line, print the $-string in DE, blank line.
PRINT_BANNER_MSG:
        PUSH DE                          ; $04CB  D5
PRINT_BANNER_1:
        CALL PUT_CRLF                    ; $04CC  CD C2 04
PRINT_BANNER_2:
        CALL PUT_CRLF                    ; $04CF  CD C2 04
PRINT_BANNER_3:
        POP DE                           ; $04D2  D1
; [AI] PRINT_STRING: print the $-terminated string at DE via BDOS fn 9.
PRINT_STRING:
        LD C,$09                         ; $04D3  0E 09     ; [AI] BDOS fn 9 = print $-string
PRINT_STRING_TAIL:
        JP BDOS_VEC                      ; $04D5  C3 05 00
; [AI] PROMPT_TWO_DRIVES: if Apple and CP/M drives differ, show the two-drive
; [AI] "Insert Apple in Z:, CP/M in Q:" prompt and wait for RETURN.
PROMPT_TWO_DRIVES:
        LD HL,(APPLE_DRIVE)              ; $04D8  2A 11 05  ; [AI] L=Apple drive, H=CP/M drive
        LD A,L                           ; $04DB  7D
        CP H                             ; $04DC  BC
        RET Z                            ; $04DD  C8        ; [AI] same drive -> use the single-drive prompt instead
        LD DE,STR_INSERT_BOTH            ; $04DE  11 39 06  ; [AI] two-drive insert prompt (with patched Z:/Q:)
        CALL PRINT_STRING_AND_WAIT       ; $04E1  CD F3 04
        CALL PUT_2CRLF                   ; $04E4  CD BF 04
        LD DE,STR_WORKING                ; $04E7  11 17 07  ; [AI] "Working..."
        JP PRINT_STRING                  ; $04EA  C3 D3 04
; [AI] PROMPT_IF_SAME_DRIVE: when Apple and CP/M are the SAME physical drive, print
; [AI] DE (e.g. "Insert Apple/CP/M disk and hit RETURN") and wait for the user.
PROMPT_IF_SAME_DRIVE:
        LD HL,(APPLE_DRIVE)              ; $04ED  2A 11 05
        LD A,L                           ; $04F0  7D
        CP H                             ; $04F1  BC
        RET NZ                           ; $04F2  C0        ; [AI] two different drives -> no swap needed
; [AI] PRINT_STRING_AND_WAIT: print DE then block until a key is pressed.
PRINT_STRING_AND_WAIT:
        PUSH BC                          ; $04F3  C5
        CALL PRINT_STRING                ; $04F4  CD D3 04
        CALL FLUSH_KBD                   ; $04F7  CD AC 01  ; [AI] wait for RETURN/keypress
        POP BC                           ; $04FA  C1
        RET                              ; $04FB  C9
; [AI] PUT_CHAR: write the character in A to the console via BDOS fn 2, preserving
; [AI] all registers.
PUT_CHAR:
        PUSH AF                          ; $04FC  F5
PUT_CHAR_1:
        PUSH BC                          ; $04FD  C5
PUT_CHAR_2:
        PUSH DE                          ; $04FE  D5
PUT_CHAR_3:
        PUSH HL                          ; $04FF  E5
PUT_CHAR_4:
        LD E,A                           ; $0500  5F        ; [AI] E = char for BDOS
PUT_CHAR_5:
        LD C,$02                         ; $0501  0E 02     ; [AI] BDOS fn 2 = console output
PUT_CHAR_6:
        CALL BDOS_VEC                    ; $0503  CD 05 00
PUT_CHAR_7:
        POP HL                           ; $0506  E1
PUT_CHAR_8:
        POP DE                           ; $0507  D1
PUT_CHAR_9:
        POP BC                           ; $0508  C1
PUT_CHAR_10:
        POP AF                           ; $0509  F1
PUT_CHAR_11:
        RET                              ; $050A  C9

; [AI] ===== Working storage (variables) =====
DIR_ENTRY_IDX:                                                   ; [AI] current catalog-entry offset within a sector
        DEFB    $B7                                              ; $050B
DIR_NEXT_TS:                                                     ; [AI] track/sector link to next catalog sector
        DEFB    $00,$00                                          ; $050C
DIR_FILE_TYPE:                                                   ; [AI] Apple file-type byte of the current entry/file
        DEFB    $00                                              ; $050E
DIR_FILE_TS:                                                     ; [AI] (also NEXT_TS_LIST during copy) first track/sector of the file's T/S list
        DEFB    $00,$00                                          ; $050F
APPLE_DRIVE:                                                     ; [AI] Apple side drive number (0-based)
        DEFB    $01                                              ; $0511
APPLE_DRIVE_2:                                                   ; [AI] CP/M side drive number (0-based)
        DEFB    $00                                              ; $0512
SECT_COUNT:                                                      ; [AI] count of Apple sectors buffered, awaiting flush
        DEFB    $00                                              ; $0513
DIR_REC_LO:                                                      ; [AI] saved FCB position byte (low)
        DEFB    $00                                              ; $0514
DIR_REC_HI:                                                      ; [AI] saved FCB current-record byte (high)
        DEFB    $00                                              ; $0515
CPM_BUF_PTR:                                                     ; [AI] CP/M-side data buffer pointer for sector reads
        DEFB    $00                                              ; $0516
TS_PAGE:                                                         ; [AI] running 6502 buffer page for sector reads
        DEFB    $00                                              ; $0517
TS_LIST_IDX:                                                     ; [AI] index into the current track/sector list
        DEFB    $00                                              ; $0518
MAX_SECTORS:                                                     ; [AI] sectors that fit in the TPA buffer before a flush
        DEFS    41, $00    ; $0519  fill                          ; [AI] MAX_SECTORS is byte $0519; $051A-$0541 is reserved scratch

; [AI] ===== Sector-skew tables (DOS 3.3 logical->physical) and RWTS dispatch data =====
; [AI] APPLE_SKEW_A also doubles as the reset stack base (LD SP at $011C/$03F9).
; [AI] Index [0..15] maps a logical sector to its physical sector on the track.
APPLE_SKEW_A:
        DEFB    $00,$0E,$0D,$0C,$0B,$0A,$09                      ; $0542
        DEFW    STR_FILE_NOT_FOUND       ; $0549
        DEFW    PUT_CHAR_7               ; $054B
        DEFW    OPEN_CPM_FCB             ; $054D
        DEFB    $02,$01,$0F                                      ; $054F
APPLE_SKEW_B:                                                    ; [AI] identity table (no skew): 00,01,02,...
        DEFW    MAIN                     ; $0552
        DEFB    $02,$03,$04,$05,$06,$07,$08,$09,$0A,$0B,$0C      ; $0554
APPLE_SKEW_C:                                                    ; [AI] alternate DOS 3.3 read skew table
        DEFB    $00,$0F,$07,$03                                  ; $055F
        DEFW    COPY_HAVE_CPM_NAME       ; $0563
        DEFB    $06,$0D                                          ; $0565
        DEFW    CALC_MAX_SECTORS         ; $0567
        DEFB    $08,$0C,$04                                      ; $0569

